sql:
SELECT COUNT(*)
FROM users
WHERE last_login < date('now', '-3 month');

SELECT SUM(duration) AS TotalTripDuration
FROM trips
WHERE user_id IN (
    SELECT user_id 
    FROM subscriptions
);

external_knowledge:
- 'dormant travelers' refers to users who have not renewed their subscription;
- 'drifted away from the ship' means they do not have an active subscription at the moment;
- 'last known ports of call' refers to the date of their last trip;
- 'total voyages' indicates the total number of trips they have taken.

- 'More commonly seen' implies a higher count of bikes with the same model; 
- 'Typical battery condition' refers to the average battery level, which indicates the general state of battery power for the bike models in question; 
- 'Latest time they were serviced' means the most recent date of the last maintenance check.

sql:
SELECT COUNT(trip_id) AS num_trips_started, AVG(distance) AS avg_distance
FROM trips
WHERE start_station = 'Beale at Market';

external_knowledge:
- "Typical distance" refers to the average distance;
- "Members with a subscription" refers to users with a 'Subscriber' type subscription;
- 'Beale at Market' is the specific starting station for the trips in question.

- "seasoned travelers" refers to users with a 'Subscriber' type subscription;
- "origins" and "destinations" refer to the start and end stations;
- "vessels of time" metaphorically refers to the bikes used in the trips;
- "whispering the duration of each voyage" refers to the trip duration;

sql:
SELECT DISTINCT bike_number
FROM trips
WHERE start_date >= DATE('now', '-30 days');

external_knowledge:
- "frequent travelers" refers to users who have taken more than 10 trips;
- "several trips between specific terminals" refers to trips starting from terminals 64, 65, and 66, and ending at terminals 47, 48, and 49;
- "paid by their mobile devices" means they used 'Mobile Payment';
- "covered a significant distance" means the average distance traveled is more than 1 unit;
- "a considerable amount" means the total payment amount is more than 50 units.

sql:
SELECT SUM(payment_amount) 
FROM trips 
WHERE subscription_type = 'Casual';
